def transition(state, action):
    s = dict(state)
    name = action.get("name") if isinstance(action, dict) else None
    subtasks = [dict(t) for t in s.get("subtasks", [])]

    # Every attempted action is a step, whether or not it changes structure.
    s["steps"] = int(s.get("steps", 0)) + 1

    if name == "plan":
        # Decompose the goal -- only from the unplanned phase, only once.
        if s.get("phase") == "unplanned" and not subtasks:
            blueprint = ["clarify requirements", "design approach",
                         "implement solution", "verify result"]
            subtasks = [{"id": i + 1, "desc": d, "status": "pending"}
                        for i, d in enumerate(blueprint)]
            s["phase"] = "executing"
            s["cursor"] = 0
            s["plan_version"] = 1

    elif name == "execute":
        # Work the next pending subtask; only while actively executing.
        if s.get("phase") == "executing":
            idx = -1
            for i in range(len(subtasks)):
                if subtasks[i]["status"] == "pending":
                    idx = i
                    break
            if idx >= 0:
                brittle = (subtasks[idx]["desc"] == "implement solution"
                           and int(s.get("plan_version", 0)) < 2)
                if brittle:
                    # Execution reveals the plan was insufficient.
                    subtasks[idx]["status"] = "failed"
                    s["phase"] = "replanning"
                else:
                    subtasks[idx]["status"] = "done"
                    s["cursor"] = idx + 1

    elif name == "replan":
        # Recover: reopen failed subtasks and revise the plan.
        if s.get("phase") in ("executing", "replanning"):
            changed = False
            for t in subtasks:
                if t["status"] == "failed":
                    t["status"] = "pending"
                    changed = True
            if changed:
                s["plan_version"] = int(s.get("plan_version", 0)) + 1
                s["phase"] = "executing"

    elif name == "complete":
        # Finalize only when the whole plan is done.
        if subtasks and all(t["status"] == "done" for t in subtasks):
            s["phase"] = "done"
            s["completed"] = True

    # Keep the derived counts in sync with the subtask list.
    s["subtasks"] = subtasks
    s["done_count"] = sum(1 for t in subtasks if t["status"] == "done")
    s["pending_count"] = sum(1 for t in subtasks if t["status"] == "pending")
    s["failed_count"] = sum(1 for t in subtasks if t["status"] == "failed")
    return s

