def perceive(data):
    text = data if isinstance(data, str) else str(data)
    out = {}
    for line in text.splitlines():
        if ":" in line:
            key, value = line.split(":", 1)
            if key.strip().lower() == "goal":
                out["goal"] = value.strip()
    return out
